  ('fire-eq-tech-moex-02750', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '緊急廣播設備之配線，除依屋內線路裝置規則外，不得與其他電線共用管槽。但電線管槽內之電線用於 多少伏特以下之弱電回路者，不在此限？', '["24", "60", "110", "220"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
